import "evtlib";
// The `declare module` block carries no explicit `export`, so tsc's ambient
// auto-export rule exports every top-level member ‚Äî `DrawEvents` becomes an
// importable member of "evtlib". `DrawStop extends LeafletEvent` resolves the
// base against evtlib's own exports.
declare module "evtlib" {
  namespace DrawEvents {
    interface DrawStop extends LeafletEvent {
      layerType: string;
    }
  }
}
